def count_devine_surname(people_list):
    return sum(1 for person in people_list if person.get('surname') == 'Devine')

# Example usage:
people = [
    {'name': 'Alan Devine', 'surname': 'Devine'},
    {'name': 'John Smith', 'surname': 'Smith'},
    {'name': 'Graeme Devine', 'surname': 'Devine'}
]
print(count_devine_surname(people))  # Output: 2
